"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Contact ──

@router.get("/contacts", response_model=list[schemas.ContactResponse])
def list_contacts(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Contact).offset(skip).limit(limit).all()

@router.get("/contacts/{item_id}", response_model=schemas.ContactResponse)
def get_contact(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Contact).filter(models.Contact.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Contact not found")
    return obj

@router.post("/contacts", response_model=schemas.ContactResponse, status_code=201)
def create_contact(data: schemas.ContactCreate, db: Session = Depends(get_db)):
    import uuid as _uuid
    payload = data.model_dump()
    payload.setdefault('id', str(_uuid.uuid4()))
    obj = models.Contact(**payload)
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/contacts/{item_id}", response_model=schemas.ContactResponse)
def update_contact(item_id: str, data: schemas.ContactUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Contact).filter(models.Contact.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Contact not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/contacts/{item_id}", status_code=204)
def delete_contact(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Contact).filter(models.Contact.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Contact not found")
    db.delete(obj)
    db.commit()

